parameters.jsCode:
const input = $input.first().json;

const text = String(
  input.message ||
  input.raw_text ||
  input.text ||
  input.content ||
  ''
).trim();

const lowerText = text.toLowerCase();

const dbState =
  input.state ||
  input.user_state ||
  'idle';

let effectiveState = dbState || 'idle';

const isSearchCommand =
  lowerText === '/search' ||
  lowerText.startsWith('/search ');

const isCancelCommand =
  lowerText === '/cancel' ||
  lowerText === 'cancel';

if (isCancelCommand) {
  effectiveState = 'command_cancel';
} else if (isSearchCommand) {
  effectiveState = 'command_search';
} else if (dbState === 'waiting_search_query') {
  effectiveState = 'waiting_search_query';
} else if (!effectiveState) {
  effectiveState = 'idle';
}

const searchQueryFromCommand = isSearchCommand
  ? text.replace(/^\/search(@\w+)?/i, '').trim()
  : '';

return [
  {
    json: {
      ...input,
      state: dbState,
      effective_state: effectiveState,
      is_search_command: isSearchCommand,
      search_query: searchQueryFromCommand,
      has_search_query: searchQueryFromCommand.length > 0
    }
  }
];

const trigger = $('Telegram Trigger').first().json;
const msg = trigger.message;

if (!msg) {
  throw new Error('No Telegram message found in Telegram Trigger');
}

const userId = msg.from.id;
const chatId = msg.chat.id;

function basePayload(extra = {}) {
  return {
    user_id: userId,
    chat_id: chatId,

    message: null,
    content: null,
    message_type: 'text',

    file_id: null,
    file_unique_id: null,
    file_name: null,
    mime_type: null,
    caption: null,
    telegram_file_path: null,
    file_url: null,

    latitude: null,
    longitude: null,
    location_title: null,
    location_address: null,
    maps_url: null,

    ...extra
  };
}

// Text
if (msg.text) {
  return [
    {
      json: basePayload({
        message_type: 'text',
        message: msg.text,
        content: msg.text
      })
    }
  ];
}

// Location
if (msg.location) {
  const lat = msg.location.latitude;
  const lon = msg.location.longitude;
  const mapsUrl = `https://maps.google.com/?q=${lat},${lon}`;

  return [
    {
      json: basePayload({
        message_type: 'location',
        message: `Shared location: ${mapsUrl}`,
        content: `Shared location: ${mapsUrl}`,
        latitude: lat,
        longitude: lon,
        location_title: msg.venue?.title || null,
        location_address: msg.venue?.address || null,
        maps_url: mapsUrl
      })
    }
  ];
}

// Venue
// Telegram venue usually also contains location
if (msg.venue) {
  const lat = msg.venue.location.latitude;
  const lon = msg.venue.location.longitude;
  const mapsUrl = `https://maps.google.com/?q=${lat},${lon}`;

  return [
    {
      json: basePayload({
        message_type: 'location',
        message: `Shared venue: ${msg.venue.title || 'Location'}\n${mapsUrl}`,
        content: `Shared venue: ${msg.venue.title || 'Location'}\n${mapsUrl}`,
        latitude: lat,
        longitude: lon,
        location_title: msg.venue.title || null,
        location_address: msg.venue.address || null,
        maps_url: mapsUrl
      })
    }
  ];
}

// Video note / Telegram circle video
if (msg.video_note) {
  return [
    {
      json: basePayload({
        message_type: 'video_note',
        message: '[video note]',
        content: '[video note]',
        file_id: msg.video_note.file_id,
        file_unique_id: msg.video_note.file_unique_id,
        mime_type: 'video/mp4',
        caption: null
      })
    }
  ];
}


// Photo
if (msg.photo && msg.photo.length > 0) {
  const photo = msg.photo[msg.photo.length - 1];

  return [
    {
      json: basePayload({
        message_type: 'photo',
        message: msg.caption || '[photo]',
        content: msg.caption || '[photo]',
        file_id: photo.file_id,
        file_unique_id: photo.file_unique_id,
        caption: msg.caption || null
      })
    }
  ];
}

// Document / file
if (msg.document) {
  return [
    {
      json: basePayload({
        message_type: 'document',
        message: msg.caption || msg.document.file_name || '[document]',
        content: msg.caption || msg.document.file_name || '[document]',
        file_id: msg.document.file_id,
        file_unique_id: msg.document.file_unique_id,
        file_name: msg.document.file_name || null,
        mime_type: msg.document.mime_type || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Voice
if (msg.voice) {
  return [
    {
      json: basePayload({
        message_type: 'voice',
        message: msg.caption || '[voice message]',
        content: msg.caption || '[voice message]',
        file_id: msg.voice.file_id,
        file_unique_id: msg.voice.file_unique_id,
        mime_type: msg.voice.mime_type || 'audio/ogg',
        caption: msg.caption || null
      })
    }
  ];
}

// Audio
if (msg.audio) {
  return [
    {
      json: basePayload({
        message_type: 'audio',
        message: msg.caption || msg.audio.file_name || msg.audio.title || '[audio]',
        content: msg.caption || msg.audio.file_name || msg.audio.title || '[audio]',
        file_id: msg.audio.file_id,
        file_unique_id: msg.audio.file_unique_id,
        file_name: msg.audio.file_name || msg.audio.title || null,
        mime_type: msg.audio.mime_type || null,
        caption: msg.caption || null
      })
    }
  ];
}

// Video
if (msg.video) {
  return [
    {
      json: basePayload({
        message_type: 'video',
        message: msg.caption || '[video]',
        content: msg.caption || '[video]',
        file_id: msg.video.file_id,
        file_unique_id: msg.video.file_unique_id,
        mime_type: msg.video.mime_type || 'video/mp4',
        caption: msg.caption || null
      })
    }
  ];
}

// Fallback
return [
  {
    json: basePayload({
      message_type: 'unknown',
      message: '[unrecognized message]',
      content: '[unrecognized message]'
    })
  }
];

const input = $input.first().json;

if (!input.callback_query) {
  throw new Error('This node expects callback_query');
}

const data = input.callback_query.data;
// пример: download_msg:123

const messageId = Number(data.split(':')[1]);

if (!messageId) {
  throw new Error(`Invalid message id in callback data: ${data}`);
}

return [
  {
    json: {
      user_id: input.callback_query.from.id,
      chat_id: input.callback_query.message.chat.id,
      message_id: messageId,
      callback_query_id: input.callback_query.id
    }
  }
];

const items = $input.all();

const trigger = $('Telegram Trigger').first().json;

const fallbackChatId =
  trigger.callback_query?.message?.chat?.id ||
  trigger.callback_query?.from?.id ||
  trigger.message?.chat?.id ||
  trigger.message?.from?.id;

if (items.length === 0) {
  return [
    {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: fallbackChatId,
          text: 'File not found or you do not have access ⚠️'
        }
      }
    }
  ];
}

const data = items[0].json;

const chatId = data.chat_id || fallbackChatId;
const messageType = data.message_type || 'document';

const caption =
  data.caption ||
  data.file_name ||
  data.content ||
  '';

if (!data.file_id && messageType !== 'location') {
  return [
    {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: chatId,
          text: 'This message has no downloadable file ⚠️'
        }
      }
    }
  ];
}

// Location is not a file, send it as a map link
if (messageType === 'location') {
  const title = data.location_title ? `\n${data.location_title}` : '';
  const address = data.location_address ? `\n${data.location_address}` : '';

  const coords =
    data.latitude !== null &&
    data.latitude !== undefined &&
    data.longitude !== null &&
    data.longitude !== undefined
      ? `\nCoordinates: ${data.latitude}, ${data.longitude}`
      : '';

  const maps = data.maps_url ? `\nGoogle Maps: ${data.maps_url}` : '';

  return [
    {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: chatId,
          text: `📍 Location${title}${address}${coords}${maps}`.trim(),
          disable_web_page_preview: false
        }
      }
    }
  ];
}

// Photo
if (messageType === 'photo') {
  const body = {
    chat_id: chatId,
    photo: data.file_id
  };

  if (data.caption) {
    body.caption = data.caption;
  }

  return [
    {
      json: {
        api_method: 'sendPhoto',
        body
      }
    }
  ];
}

// Video
if (messageType === 'video') {
  const body = {
    chat_id: chatId,
    video: data.file_id
  };

  if (caption) {
    body.caption = caption;
  }

  return [
    {
      json: {
        api_method: 'sendVideo',
        body
      }
    }
  ];
}

// Telegram circle video / video note
if (messageType === 'video_note') {
  return [
    {
      json: {
        api_method: 'sendVideoNote',
        body: {
          chat_id: chatId,
          video_note: data.file_id
        }
      }
    }
  ];
}

// Voice message
if (messageType === 'voice') {
  const body = {
    chat_id: chatId,
    voice: data.file_id
  };

  if (caption && caption !== '[voice message]') {
    body.caption = caption;
  }

  return [
    {
      json: {
        api_method: 'sendVoice',
        body
      }
    }
  ];
}

// Audio file
if (messageType === 'audio') {
  const body = {
    chat_id: chatId,
    audio: data.file_id
  };

  if (caption) {
    body.caption = caption;
  }

  return [
    {
      json: {
        api_method: 'sendAudio',
        body
      }
    }
  ];
}

// Document / PDF / Word / Excel / unknown file
const body = {
  chat_id: chatId,
  document: data.file_id
};

if (caption) {
  body.caption = caption;
}

return [
  {
    json: {
      api_method: 'sendDocument',
      body
    }
  }
];

