const input = $input.first().json;

return [
  {
    json: {
      user_id: input.user_id,
      chat_id: input.chat_id,
      text:
`🔎 What do you want to find?

Send a text query or a voice message.

Examples:
• resume
• NAYA salary
• bank document
• photo from conference
• n8n docker`,
      inline_keyboard: [
        [
          {
            text: '❌ Cancel search',
            callback_data: 'action:cancel_search'
          }
        ]
      ]
    }
  }
];

const stateInput = $input.first().json || {};

// Берем оригинальный Telegram update из Telegram Trigger,
// потому что после switch state в input может остаться только state.
let update = {};

try {
  update = $('Telegram Trigger').first().json || {};
} catch (e) {
  update = {};
}

// Fallback: если текущий input уже содержит message
if (!update.message && !update.edited_message && !update.callback_query) {
  update = stateInput;
}

const message =
  update.message ||
  update.edited_message ||
  stateInput.message ||
  stateInput.edited_message ||
  {};

const from = message.from || {};
const chat = message.chat || {};

const userId =
  stateInput.user_id ||
  update.user_id ||
  from.id ||
  null;

const chatId =
  stateInput.chat_id ||
  update.chat_id ||
  chat.id ||
  userId ||
  null;

if (!userId || !chatId) {
  throw new Error(
    `Cannot detect user_id or chat_id in Prepare search query payload. ` +
    `Input keys: ${Object.keys(stateInput).join(', ')}. ` +
    `Update keys: ${Object.keys(update).join(', ')}`
  );
}

let messageType = 'text';
let searchQuery = '';

let fileId = null;
let fileUniqueId = null;
let fileName = null;
let mimeType = null;
let fileSize = null;

const text = String(message.text || '').trim();

if (text) {
  messageType = 'text';

  searchQuery = text
    .replace(/^\/search\s*/i, '')
    .trim();
}

else if (message.voice) {
  messageType = 'voice';

  fileId = message.voice.file_id || null;
  fileUniqueId = message.voice.file_unique_id || null;
  fileName = null;
  mimeType = message.voice.mime_type || 'audio/ogg';
  fileSize = message.voice.file_size || null;
}

else if (message.audio) {
  messageType = 'audio';

  fileId = message.audio.file_id || null;
  fileUniqueId = message.audio.file_unique_id || null;
  fileName = message.audio.file_name || message.audio.title || null;
  mimeType = message.audio.mime_type || 'audio/mpeg';
  fileSize = message.audio.file_size || null;
}

else {
  messageType = 'unsupported';
}

const isTextSearch =
  messageType === 'text' &&
  searchQuery.length > 0;

const isAudioSearch =
  ['voice', 'audio'].includes(messageType) &&
  !!fileId;

const maxSearchAudioBytes = 1024 * 1024; // 1 MB

const audioTooLarge =
  isAudioSearch &&
  Number(fileSize || 0) > maxSearchAudioBytes;

function formatBytes(bytes) {
  const n = Number(bytes || 0);

  if (!n || Number.isNaN(n)) {
    return 'unknown size';
  }

  if (n < 1024) {
    return `${n} B`;
  }

  if (n < 1024 * 1024) {
    return `${(n / 1024).toFixed(1)} KB`;
  }

  return `${(n / 1024 / 1024).toFixed(1)} MB`;
}

let searchError = null;

if (!isTextSearch && !isAudioSearch) {
  searchError =
    'Please send a text search query or a short voice message.';
}

if (audioTooLarge) {
  searchError =
    `Search voice message is too large ⚠️\n\n` +
    `Please send audio up to 1 MB.\n\n` +
    `Your audio size: ${formatBytes(fileSize)}.`;
}

return [
  {
    json: {
      ...stateInput,

      user_id: userId,
      chat_id: chatId,

      state: stateInput.state || null,
      effective_state: stateInput.effective_state || stateInput.state || null,

      message_type: messageType,

      search_query: searchQuery,
      search_query_ready: isTextSearch,

      needs_search_audio_transcription:
        isAudioSearch && !audioTooLarge,

      search_error: searchError,

      file_id: fileId,
      file_unique_id: fileUniqueId,
      file_name: fileName,
      mime_type: mimeType,
      file_size: fileSize,
      file_size_human: formatBytes(fileSize),

      max_search_audio_bytes: maxSearchAudioBytes
    }
  }
];

const input = $input.first().json;

if (!input.callback_query) {
  throw new Error('This node expects callback_query');
}

return [
  {
    json: {
      user_id: input.callback_query.from.id,
      chat_id: input.callback_query.message.chat.id,
      callback_query_id: input.callback_query.id,
      telegram_message_id: input.callback_query.message.message_id
