  firstInput = {};
}

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return null;
}

const userId = firstValue(
  firstInput.user_id,
  trigger.message?.from?.id,
  trigger.callback_query?.from?.id,
  trigger.callback_query?.message?.chat?.id,
  trigger.message?.chat?.id
);

const chatId = firstValue(
  firstInput.chat_id,
  trigger.message?.chat?.id,
  trigger.callback_query?.message?.chat?.id,
  trigger.callback_query?.from?.id,
  trigger.message?.from?.id,
  userId
);

if (!chatId) {
  throw new Error('Cannot detect chat_id for keywords list');
}

// Remove fake PostgreSQL empty output item: { success: true }
const keywordRows = items
  .map(item => item.json || {})
  .filter(row => {
    return (
      row.keyword !== undefined &&
      row.keyword !== null &&
      String(row.keyword).trim() !== ''
    );
  });

if (keywordRows.length === 0) {
  return [
    {
      json: {
        user_id: userId,
        chat_id: chatId,
        text:
`🔑 Keywords

No keywords found yet.

Save a few messages first, or wait until AI analysis finishes.`
      }
    }
  ];
}

const sorted = keywordRows
  .map(row => ({
    keyword: String(row.keyword || '').trim(),
    usage_count: Number(row.usage_count || 0)
  }))
  .filter(row => row.keyword)
  .sort((a, b) => {
    if (b.usage_count !== a.usage_count) {
      return b.usage_count - a.usage_count;
    }

    return a.keyword.localeCompare(b.keyword);
  });

const keywordText = sorted
  .map(row => {
    return row.usage_count > 1
      ? `${row.keyword}(${row.usage_count})`
      : row.keyword;
  })
  .join(', ');

const header = `🔑 Keywords (${sorted.length})`;

let text = `${header}\n\n${keywordText}`;

const maxLength = 3800;

if (text.length <= maxLength) {
  return [
    {
      json: {
        user_id: userId,
        chat_id: chatId,
        text
      }
    }
  ];
}

// Split long keyword string into Telegram-safe chunks
const chunks = [];
let remaining = keywordText;

while (remaining.length > 0) {
  let cutAt = Math.min(maxLength - header.length - 60, remaining.length);

  if (remaining.length > cutAt) {
    const lastComma = remaining.lastIndexOf(', ', cutAt);
    if (lastComma > 0) {
      cutAt = lastComma;
    }
  }

  const chunk = remaining.slice(0, cutAt).trim().replace(/,\s*$/, '');
  chunks.push(chunk);

  remaining = remaining.slice(cutAt).replace(/^,\s*/, '').trim();
}

return chunks.map((chunk, index) => ({
  json: {
    user_id: userId,
    chat_id: chatId,
    text: chunks.length > 1
      ? `${header}\n\nPart ${index + 1}/${chunks.length}\n\n${chunk}`
      : `${header}\n\n${chunk}`
  }
}));

