const original = $('Prepare search query payload').first().json || {};
const getFile = $('Telegram getFile search audio').first().json || {};

const item = $input.first();
const binaryMeta = item.binary?.data;

if (!binaryMeta) {
  return [
    {
      json: {
        ...original,
        search_audio_transcription_status: 'failed',
        search_audio_error: 'No binary audio data found',
        search_query: '',
        search_query_ready: false
      }
    }
  ];
}

let audioBase64;

try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  audioBase64 = buffer.toString('base64');
} catch (error) {
  return [
    {
      json: {
        ...original,
        search_audio_transcription_status: 'failed',
        search_audio_error: error.message,
        search_query: '',
        search_query_ready: false
      }
    }
  ];
}

const messageType = String(original.message_type || 'voice').toLowerCase();

function detectMimeType(original, binaryMeta, getFile) {
  const originalMime = original.mime_type || '';
  const binaryMime = binaryMeta?.mimeType || '';

  if (originalMime && originalMime !== 'application/octet-stream') {
    return originalMime;
  }

  if (binaryMime && binaryMime !== 'application/octet-stream') {
    return binaryMime;
  }

  const filePath = String(getFile?.result?.file_path || '').toLowerCase();

  if (filePath.endsWith('.ogg')) return 'audio/ogg';
  if (filePath.endsWith('.oga')) return 'audio/ogg';
  if (filePath.endsWith('.mp3')) return 'audio/mpeg';
  if (filePath.endsWith('.m4a')) return 'audio/x-m4a';
  if (filePath.endsWith('.wav')) return 'audio/wav';
  if (filePath.endsWith('.webm')) return 'audio/webm';
  if (filePath.endsWith('.mp4')) return 'audio/mp4';

  if (messageType === 'voice') return 'audio/ogg';
  if (messageType === 'audio') return 'audio/mpeg';

  return 'audio/ogg';
}

const mimeType = detectMimeType(original, binaryMeta, getFile);

const supportedMimeTypes = [
  'audio/ogg',
  'audio/mpeg',
  'audio/mp3',
  'audio/wav',
  'audio/webm',
  'audio/mp4',
  'audio/aac',
  'audio/flac',
  'audio/x-wav',
  'audio/x-m4a',
  'application/ogg'
];

if (!supportedMimeTypes.includes(mimeType)) {
  return [
    {
      json: {
        ...original,
        mime_type: mimeType,
        search_audio_transcription_status: 'unsupported',
        search_audio_error: `Unsupported audio MIME type: ${mimeType}`,
        search_query: '',
        search_query_ready: false
      }
    }
  ];
}

const prompt = `
You are converting a Telegram voice/audio message into a short search query for a personal memory bot.

Task:
1. Transcribe the user's spoken request.
2. Extract only the useful search keywords.
3. Return a short search query, not a sentence.
4. Keep names, brands, places, document types, dates, numbers, and important nouns.
5. Remove filler words like "please find", "search for", "show me", "I need".
6. If the user speaks Russian, Hebrew, English, Arabic, or mixed language, keep the useful words in the original language when important.
7. If there is no clear searchable content, return an empty search_query.

Return only valid JSON.
Do not use markdown.
Do not wrap in code fences.

Return exactly this JSON:

{
  "transcript": "full short transcript or null",
  "search_query": "clean search keywords only",
  "language": "ru | en | he | ar | mixed | unknown",
  "confidence": 0.85
}
`.trim();

const requestBody = {
  contents: [
    {
      parts: [
        {
          text: prompt
        },
        {
          inline_data: {
            mime_type: mimeType,
            data: audioBase64
          }
        }
      ]
    }
  ],
  generationConfig: {
    temperature: 0.1,
    responseMimeType: 'application/json'
  }
};

return [
  {
    json: {
      ...original,
      mime_type: mimeType,
      telegram_file_path: getFile?.result?.file_path || null,
      gemini_request_body: requestBody,
      search_audio_transcription_status: 'prepared'
    }
  }
];

const original = $('Prepare Gemini search audio request').first().json || {};
const input = $input.first().json || {};

function safeJsonParse(text) {
  if (!text) return null;

  let cleaned = String(text).trim();

  cleaned = cleaned
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (e2) {}
    }
  }

  return null;
}

const text =
  input.candidates?.[0]?.content?.parts
    ?.map(part => part.text || '')
    .join('\n')
    .trim() || '';

const parsed = safeJsonParse(text);

const transcript = String(parsed?.transcript || '').trim();
let searchQuery = String(parsed?.search_query || '').trim();

searchQuery = searchQuery
  .replace(/^["']|["']$/g, '')
  .replace(/\s+/g, ' ')
  .trim();

const confidence = Number(parsed?.confidence || 0);

const isReady =
  searchQuery.length >= 2 &&
  confidence >= 0.2;

return [
  {
    json: {
      ...original,

      search_query: searchQuery,
      search_query_ready: isReady,

      search_audio_transcription_status: isReady ? 'success' : 'empty',
      search_audio_transcript: transcript,
      search_audio_language: parsed?.language || 'unknown',
      search_audio_confidence: confidence,

      search_audio_raw_response: text,

      search_error: isReady
        ? null
        : 'I could not understand the voice search query. Please type the search words or send a clearer voice message.'
    }
  }
];

