const input = $input.first().json;

const chatId = input.chat_id;
const sessionId = input.search_session_id;

const savedTotal = Number(input.saved_results_count ?? 0);
const rawTotal = Number(input.total_count ?? 0);
const topLimit = Number(input.top_relevant_limit ?? 10);
const query = String(input.search_query || '').trim();

const keyboard = [];

if (savedTotal > 0) {
  keyboard.push([
    {
      text: `📋 Show all (${savedTotal})`,
      callback_data: `search_show_all:${sessionId}`
    }
  ]);

  if (savedTotal > topLimit) {
    keyboard.push([
      {
        text: `⭐ Show top ${topLimit}`,
        callback_data: `search_show_top:${sessionId}`
      }
    ]);
  }
}

keyboard.push([
  {
    text: '🔎 Search again',
    callback_data: 'action:search'
  }
]);

let text;

if (savedTotal > 0) {
  text =
`Found ${savedTotal} message${savedTotal === 1 ? '' : 's'}.

Search query:
${query || '—'}

Choose what to show:`;
} else if (rawTotal > 0) {
  text =
`Search found ${rawTotal} possible result${rawTotal === 1 ? '' : 's'}, but none could be saved for display.

Search query:
${query || '—'}

Please try another search.`;
} else {
  text =
`Nothing found.

Search query:
${query || '—'}

You can try another search.`;
}

return [
  {
    json: {
      chat_id: chatId,
      text,
      inline_keyboard: keyboard,
      search_session_id: sessionId,
      saved_results_count: savedTotal,
      raw_results_count: rawTotal
    }
  }
];

const input = $input.first().json;

const callback = input.callback_query;

if (!callback) {
  throw new Error('This node expects callback_query');
