const data = String(callback.data || '');

let mode = null;
let sessionId = null;

if (data.startsWith('search_show_all:')) {
  mode = 'all';
  sessionId = data.replace('search_show_all:', '').trim();
}

if (data.startsWith('search_show_top:')) {
  mode = 'top';
  sessionId = data.replace('search_show_top:', '').trim();
}

if (!mode || !sessionId) {
  throw new Error(`Unsupported search results callback: ${data}`);
}

return [
  {
    json: {
      user_id: callback.from.id,
      chat_id: callback.message.chat.id,
      callback_query_id: callback.id,
      telegram_message_id: callback.message.message_id,
      search_session_id: sessionId,
      mode
    }
  }
];

const rawItems = $input.all();

const trigger = $('Telegram Trigger').first().json;

const fallbackChatId =
  trigger.callback_query?.message?.chat?.id ||
  trigger.callback_query?.from?.id ||
  trigger.message?.chat?.id ||
  trigger.message?.from?.id;

function clean(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim();
}

function fromPayload(row, key) {
  const p = row.result_payload || {};
  return row[key] ?? p[key] ?? '';
}

function formatDate(value) {
  if (!value) return '';

  try {
    const d = new Date(value);

    if (Number.isNaN(d.getTime())) {
      return String(value);
    }

    const pad = n => String(n).padStart(2, '0');

    return `${pad(d.getDate())}/${pad(d.getMonth() + 1)}/${String(d.getFullYear()).slice(-2)}, ${pad(d.getHours())}:${pad(d.getMinutes())}`;
  } catch (e) {
    return String(value);
  }
}

function shorten(text, max = 900) {
  const value = clean(text).replace(/\s+/g, ' ');
  if (value.length <= max) return value;
  return value.slice(0, max - 1) + '…';
}

function getIcon(messageType, row) {
  const type = clean(messageType).toLowerCase();

  if (type === 'photo') return '🖼️';
  if (type === 'voice') return '🎙️';
  if (type === 'audio') return '🎧';
  if (type === 'video') return '🎬';
  if (type === 'video_note') return '🎥';
  if (type === 'document' || type === 'file') return '📄';

  const lat = fromPayload(row, 'latitude');
  const lon = fromPayload(row, 'longitude');

  if (lat !== '' && lon !== '') {
    return '📍';
  }

  return '💬';
}

const items = rawItems.filter(item => {
  const row = item.json || {};
  const messageId = fromPayload(row, 'message_id') || fromPayload(row, 'id');
  return !!messageId;
});

if (!items.length) {
  return [
    {
      json: {
        api_method: 'sendMessage',
        body: {
          chat_id: fallbackChatId,
          text: 'No saved search results found ⚠️\n\nPlease run a new search.'
        }
      }
    }
  ];
}

const output = [];

for (let i = 0; i < items.length; i++) {
  const row = items[i].json || {};

  const chatId =
    fromPayload(row, 'chat_id') ||
    fallbackChatId;

  const messageId =
    fromPayload(row, 'message_id') ||
    fromPayload(row, 'id');

  const topicTitle =
    clean(fromPayload(row, 'topic_title')) ||
    'No topic';

  const messageType =
    clean(fromPayload(row, 'message_type')) ||
    'text';

  const fileId = clean(fromPayload(row, 'file_id'));
  const fileName = clean(fromPayload(row, 'file_name'));
  const mapsUrl = clean(fromPayload(row, 'maps_url'));

  const content =
    clean(fromPayload(row, 'display_text')) ||
    clean(fromPayload(row, 'content')) ||
    clean(fromPayload(row, 'caption')) ||
    clean(fileName) ||
    clean(fromPayload(row, 'location_title')) ||
    clean(fromPayload(row, 'location_address')) ||
    clean(mapsUrl) ||
    clean(fromPayload(row, 'ai_summary')) ||
    '[message]';

  const position =
    Number(fromPayload(row, 'result_position')) ||
    Number(fromPayload(row, 'result_number')) ||
    i + 1;

  const total =
    Number(fromPayload(row, 'total_count')) ||
    Number(fromPayload(row, 'total_results')) ||
    items.length;

  const createdAt = fromPayload(row, 'created_at');
  const icon = getIcon(messageType, row);

  let caption =
`${position}/${total} ${icon} ${shorten(content, 500)}

Topic: ${topicTitle}
Type: ${messageType}`;

  if (createdAt) {
    caption += `\nDate: ${formatDate(createdAt)}`;
  }

  const rowButtons = [];

  if (messageId) {
    rowButtons.push({
      text: '🧠 Summary',
      callback_data: `summary_msg:${messageId}`
    });
  }

  if (mapsUrl) {
    rowButtons.push({
      text: '🗺 Map',
      url: mapsUrl
    });
  }

  if (messageId) {
    rowButtons.push({
      text: '🗑 Delete',
      callback_data: `delete_msg:${messageId}`
    });
  }

  const replyMarkup = rowButtons.length
    ? {
        inline_keyboard: [rowButtons]
      }
    : undefined;

  // PHOTO: send actual photo preview
  if (messageType === 'photo' && fileId) {
    const body = {
      chat_id: chatId,
      photo: fileId,
      caption
    };

    if (replyMarkup) {
      body.reply_markup = replyMarkup;
    }

    output.push({
      json: {
        api_method: 'sendPhoto',
        body,
        search_session_id: fromPayload(row, 'search_session_id'),
        user_id: fromPayload(row, 'user_id'),
        mode: fromPayload(row, 'mode')
      }
    });

    continue;
  }

  // DOCUMENT / FILE / AUDIO / VIDEO / VOICE: text card with Download button
  if (
    fileId &&
    messageId &&
    ['document', 'file', 'audio', 'voice', 'video', 'video_note'].includes(messageType)
  ) {
    rowButtons.unshift({
      text: '⬇️ Download',
      callback_data: `download_msg:${messageId}`
    });
  }

  const textBody = {
    chat_id: chatId,
    text: caption
  };

  if (rowButtons.length) {
    textBody.reply_markup = {
      inline_keyboard: [rowButtons]
    };
  }

  output.push({
    json: {
      api_method: 'sendMessage',
      body: textBody,
      search_session_id: fromPayload(row, 'search_session_id'),
      user_id: fromPayload(row, 'user_id'),
      mode: fromPayload(row, 'mode')
    }
  });
}

return output;

const source = $('Parse search results callback').first().json || {};

const searchSessionId = String(source.search_session_id || '').trim();
const userId = source.user_id;
const chatId = source.chat_id;
const mode = String(source.mode || 'top').trim();

if (!searchSessionId) {
  throw new Error('Missing search_session_id in Parse search results callback');
}

if (!userId) {
  throw new Error('Missing user_id in Parse search results callback');
}

if (!chatId) {
  throw new Error('Missing chat_id in Parse search results callback');
}

return [
  {
    json: {
      user_id: userId,
      chat_id: chatId,
      callback_query_id: source.callback_query_id,
      telegram_message_id: source.telegram_message_id,
      search_session_id: searchSessionId,
      mode
    }
  }
];
